jit_argb2ayuv = MaxObject("jit.argb2ayuv")
"""
jit.argb2ayuv - Convert ARGB to AYUV

Converts 4-plane char matrix a 4-plane char ARGB (alpha, red, green, blue) matrix into a 4-plane AYUV (alpha, luminance, signed chroma blue, signed chroma red) matrix. Unlike UYVY data, AYUV data has an alpha channel and full resolution chroma data.

Inlets:
  0 (matrix): in

Outlets:
  0 (matrix): out
  1 (matrix): dumpout
"""

jit_argb2grgb = MaxObject("jit.argb2grgb")
"""
jit.argb2grgb - Convert ARGB to GRGB

Converts a 4-plane char ARGB (alpha, red, green, blue) matrix into a 4-plane char GRGB (green left, red, green right, blue) matrix. Alpha channel is lost and horizontal dimension is halved to support this half red and blue chroma, macro pixel output format. The GRGB format is typically useful for conserving memory and/or bandwidth for continuous tone images with less expense than colorspace conversion.

Inlets:
  0 (matrix): in

Outlets:
  0 (matrix): out
  1 (matrix): dumpout
"""

jit_argb2uyvy = MaxObject("jit.argb2uyvy")
